package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testValueOf() {
        // Given
        String format = "DEFAULT";

        // Mocking the Predefined class
        CSVFormat.Predefined predefined = mock(CSVFormat.Predefined.class);
        CSVFormat csvFormat = mock(CSVFormat.class);
        when(predefined.getFormat()).thenReturn(csvFormat);
        when(CSVFormat.Predefined.valueOf(format)).thenReturn(predefined);

        // When
        CSVFormat result = CSVFormat.valueOf(format);

        // Then
        assertEquals(csvFormat, result);
    }
}
